'use strict'
const {db} = require('../models');
const moment = require('moment-timezone');
const { getArchivoLocal } = require('./carga_archivos.controller');
const fs = require('fs');
const path = require('path');
const wkhtmltopdf = require('wkhtmltopdf');
const { ManipuladorCadenas } = require('../middlewares/manipuladorCadenas');
const { Worker } = require('worker_threads');

async function genPdfLocal(id){
    try {
        const respuesta = await getPDF(id);
        if(respuesta != undefined){
            if(respuesta.codeError != undefined){
                return respuesta;
            }
        }
        const htmlContent = respuesta.contenido
        if(htmlContent === undefined){
            return { status: false, msg: "Error al generar Pdf"};
        }
        const options = {
            pageSize: 'A4', // Puede ser 'A4', 'Letter', 'Legal', etc.
        };
        return new Promise((resolve, reject) => {
            const buffers = [];
            
            wkhtmltopdf(htmlContent, options)
              .on('data', (chunk) => buffers.push(chunk)) // Guarda cada fragmento del PDF en un buffer
              .on('end', () => resolve(Buffer.concat(buffers))) // Combina todos los buffers en uno solo
              .on('error', reject);
        });
    } catch (error) {
      return { status: false, msg: "Error interno del servidor", error: error.toString()};
    }
}

async function showPDF(req, res){
	const { id } = req.params;
    try {
        const registroEncontrado = await db.sequelize.models.cotizaciones.findByPk(id, {paranoid: false});
        if(registroEncontrado == null){
          return res.status(400).send({ status: false, msg: "Registro no existe" });
        }
        const worker = new Worker('./controllers_hilos/cotizaciones_pdf.controller.hilo.js', {
            workerData: { idCotizacion: id }
        });
    
        worker.on('message', (result) => {
            if (result.error) {
                return res.status(500).send({ status: false, msg: "Error al generar Pdf"});
            } else {
                res.setHeader('Content-Type', 'application/pdf');
                res.setHeader('Content-Disposition', 'attachment; filename=generated.pdf');
                const pdfBuffer = Buffer.from(result);
                return res.send(pdfBuffer);
            }
        });
    
        worker.on('error', (err) => {
            return res.status(500).send({ status: false, msg: "Error al generar Pdf"});
        });
    
        worker.on('exit', (code) => {
            if (code !== 0){
                return res.status(500).send({ status: false, msg: "Error al generar Pdf"});
            }
        });
    } catch (error) {
        return res.status(500).send({ status: false, msg: "Error al generar Pdf", error: error.toString()});
    }
}

async function getPDF(idCotizacion){
	const cotizacion = await db.sequelize.models.cotizaciones.findByPk(idCotizacion, { include:['marca', 'metodo_pago', 'moneda', 'usuario_registro', 'contacto', 'cliente'],paranoid: false });
    const nameMarca = await ManipuladorCadenas.quitarAcentos(cotizacion.marca.nombre.toLowerCase())
    const nameMarcaList = nameMarca.split(" ")
    let nameTpl = ''
    if(nameMarcaList.includes('keepro') && nameMarcaList.includes('mexico')){
        nameTpl = 'cotizacion_keepro.html'
    }
    var contenido = await getTpl(nameTpl)
    contenido = await remplaceData(cotizacion,contenido)
    contenido = await cotizacionCancelada(contenido,cotizacion.deletedAt != null)
    return { status: true, contenido: contenido}
}

async function getImg(marca){
    try {
        const registroEncontrado = await db.sequelize.models.carga_archivos.findByPk(marca.archivo.id,{ paranoid: false });
        if(registroEncontrado == null){
            if(registroEncontrado.deletedAt == null){
            }
        }
        const img = await getArchivoLocal(registroEncontrado)
        if(img.status != undefined){
            return `data:image/png;base64, `
        }
        return `data:image/png;base64, ${img}`
    } catch (error) {
    return `data:image/png;base64, `
    }
}

async function getTpl(nameTpl){
    const rutaTpl = path.join(__dirname, '../tpls/comprobantes', nameTpl);
    const contenido = fs.readFileSync(rutaTpl, 'utf8');
    return contenido
}

async function remplaceData(cotizacion,tpl){
    const marca = await db.sequelize.models.marcas.findByPk(cotizacion.id_marca, { include:['archivo'],paranoid: false });
    const datoFacturacionEmisor = await db.sequelize.models.datos_facturacion.findByPk(marca.id_dato_facturacion, { include:['datos_facturacion_domicilios'],paranoid: false });
    var domicilioFiscalEmisor
    for(const domicilio of datoFacturacionEmisor.datos_facturacion_domicilios){
        if(domicilio.tipo == 'F'){
            domicilioFiscalEmisor = domicilio
        }
    }
    domicilioFiscalEmisor = await db.sequelize.models.domicilios.findByPk(domicilioFiscalEmisor.id_domicilio, {paranoid: false });
    const domicilioEmisor = `${domicilioFiscalEmisor.calle.toUpperCase()} ${domicilioFiscalEmisor.num_ext.toUpperCase()} ${domicilioFiscalEmisor.colonia.toUpperCase()}`
    const logo = await getImg(marca)
	
    const fecha = moment(cotizacion.createdAt).tz('America/Mexico_City').format('YYYY-MM-DD')
    tpl = tpl.replace(/\{\{\$logoMarca\}\}/g, logo);
    tpl = tpl.replace(/\{\{\$nombreMarca\}\}/g, marca.nombre);
    tpl = tpl.replace(/\{\{\$geDirEmpresa\}\}/g, domicilioEmisor);
    tpl = tpl.replace(/\{\{\$getCPEmpresa\}\}/g, domicilioFiscalEmisor.codigo_postal);
    tpl = tpl.replace(/\{\{\$metodoPago\}\}/g, cotizacion.metodo_pago.clave.toLowerCase() == 'ppd' ? `Credito</span><br><span style="font-weight: bold; font-family: Helvetica,Arial,sans-serif;">Días de crédito: ${cotizacion.dias_credito}</span><br>` : 'Contado</span><br>');
    
    tpl = tpl.replace(/\{\{\$folio\}\}/g, cotizacion.folio);
    tpl = tpl.replace(/\{\{\$fecha\}\}/g, fecha);
    tpl = tpl.replace(/\{\{\$descripcionMoneda\}\}/g, cotizacion.moneda.descripcion);
    const detalles = await db.sequelize.models.cotizaciones_detalles.findAll({where:{id_cotizacion:cotizacion.id}});
    const detallesHTML = await getDocumentosRAI(detalles)
    tpl = tpl.replace(/\{\{\$detalles\}\}/g, detallesHTML);
    tpl = tpl.replace(/\{\{\$agenteComercial\}\}/g, cotizacion.usuario_registro.nombre);
    try {
        tpl = tpl.replace(/\{\{\$nombreContacto\}\}/g, `${cotizacion.contacto.nombre} ${cotizacion.contacto.apellido_paterno}${cotizacion.contacto.apellido_materno != ''? ` ${cotizacion.contacto.apellido_materno}` :''}`);
        tpl = tpl.replace(/\{\{\$telefonoContacto\}\}/g, `${cotizacion.contacto.telefono}${cotizacion.contacto.extension != ''? `/${cotizacion.contacto.extension}` :''}`);
        tpl = tpl.replace(/\{\{\$emailContacto\}\}/g, `${cotizacion.contacto.email}`);
    } catch (error) {
        tpl = tpl.replace(/\{\{\$nombreContacto\}\}/g, ``);
        tpl = tpl.replace(/\{\{\$telefonoContacto\}\}/g, ``);
        tpl = tpl.replace(/\{\{\$emailContacto\}\}/g, ``);
    }
    tpl = tpl.replace(/\{\{\$comentarios\}\}/g, cotizacion.comentarios);
    tpl = tpl.replace(/\{\{\$nombreCliente\}\}/g, cotizacion.cliente.nombre);
    tpl = tpl.replace(/\{\{\$claveCliente\}\}/g, `${marca.clave}-${cotizacion.cliente.id}`);
    return tpl
}


async function getDocumentosRAI(detalles) {
    let documentosRelacionados = ''
    for(const detalle of detalles){
        const detalleData = await db.sequelize.models.cotizaciones_detalles.findByPk(detalle.id);
        const producto = await db.sequelize.models.productos.findByPk(detalleData.id_producto,{include:['producto_unidad_medida']});
        documentosRelacionados = documentosRelacionados + `
        <tr>
            <td style="vertical-align: middle; text-align: center;">${detalleData.cantidad}<br></td>
            <td style="vertical-align: middle; text-align: center;">${producto.producto_unidad_medida.clave}<br></td>
            <td style="vertical-align: middle; text-align: center;">(${producto.clave}) ${producto.descripcion}<br></td>
            <td style="vertical-align: middle; text-align: center;">${parseFloat((parseFloat(detalleData.minimo_venta) * detalleData.cantidad)).toLocaleString('es-US', { style: 'currency', currency: 'USD',  minimumFractionDigits: 2, maximumFractionDigits: 2  })}<br></td>
            <td style="vertical-align: middle; text-align: center;">${detalleData.tarifa_cliente}<br></td>
        </tr>`
    }
    
    return documentosRelacionados;
}


async function cotizacionCancelada(tpl,cancelada){
  if(!cancelada){
      return tpl.replace(/\{\{\$isCancelada\}\}/g, '');
  }
  const canceladaImg = `<img src="data:image/png;base64," style="position: absolute; margin:auto; top:0; left:0; right:0; bottom:0; opacity: 1; height: 600px">`
  return tpl.replace(/\{\{\$isCancelada\}\}/g, canceladaImg);
}



module.exports = {
    getPDF,
    genPdfLocal,
    showPDF
  }
